import React ,{UseState} from 'react'
import { useState } from 'react';
import {Card,Button,Row,Col} from 'react-bootstrap';


const Pizza = ({pizza}) => {
  const[variant,setVarient]=useState('small');
  const[quantity,setQuantity]=useState(1);
  const [show, setShow] = useState(false);

  const handleClose = () => setShow(false);
  const handleShow = () => setShow(true);

  return (
    <Card style={{ width: '18rem' ,marginTop:"10px"}}>
      <Card.Img variant="top" src={pizza.image} style={{height:"240px"}}/>
      <Card.Body>
        <Card.Title>{pizza.name}</Card.Title>
        <hr />
        <Card.Text>
        <Row>
          <Col md={6}>
            <h6>Varient</h6>
            <select value={variant} onChange={e=>setVarient(e.target.value)}>
              {
                pizza.varients.map(varient=>(
                  <option value={varient} >{varient}</option>
                ))
              }
            </select>
          </Col>
          <Col md={6}>
            <h6>Quantity</h6>
            <select value={quantity} onChange={(e)=>setQuantity(e.target.value)}>

            {[...Array(10).keys()].map((v,i)=>(
                <option value={i+1} >{i+1}</option>
            ))}
            </select>
          </Col>

        </Row>
        </Card.Text>
        <Row>
          <Col md={6}>Price : {pizza.prices[0][variant]*quantity}/- Rs</Col>
          <Col md={6}>
            <Button> Add to Cart</Button>
            </Col>
        </Row>

      </Card.Body>
    </Card>
  )
}

export default Pizza
